INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'איטום — מרפסות', '**שקיעת ריצוף במרפסת — פגיעה באיטום** — ריצוף המרפסת שקע או התרומם, מעיד על בעיה בשכבת הבסיס. השקיעה פוגעת בשיפוע הניקוז ועלולה לפגוע ביריעת האיטום מתחת.. המלצה: הסרת ריצוף פגום, בדיקת ותיקון שכבת האיטום, יצירת שכבת בסיס חדשה בשיפוע תקני, ריצוף מחדש. עלות משוערת: ₪250-₪450 (למ"ר)', '**שקיעת ריצוף במרפסת — פגיעה באיטום** — ריצוף המרפסת שקע או התרומם, מעיד על בעיה בשכבת הבסיס. השקיעה פוגעת בשיפוע הניקוז ועלולה לפגוע ביריעת האיטום מתחת.. המלצה: הסרת ריצוף פגום, בדיקת ותיקון שכבת האיטום, יצירת שכבת בסיס חדשה בשיפוע תקני, ריצוף מחדש. עלות משוערת: ₪250-₪450 (למ"ר)', 'ת"י 1556 — ריצוף מרפסת חייב להיות יציב על בסיס תקין, עם שמירה על שיפוע הניקוז', 'ת"י 1556 — ריצוף מרפסת חייב להיות יציב על בסיס תקין, עם שמירה על שיפוע הניקוז', true, 'medium');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'איטום — מרפסות', '**איטום לקוי במרפסת** — איטום מרפסת לא תקין — מים חודרים לדירה מתחת או לקיר.. המלצה: פירוק ריצוף, ביצוע איטום מחדש, ריצוף עם שיפוע. עלות משוערת: ₪120-₪280 (למ"ר)', '**איטום לקוי במרפסת** — איטום מרפסת לא תקין — מים חודרים לדירה מתחת או לקיר.. המלצה: פירוק ריצוף, ביצוע איטום מחדש, ריצוף עם שיפוע. עלות משוערת: ₪120-₪280 (למ"ר)', 'ת"י 1515.3 — מרפסות חייבות איטום מלא עם שיפוע לניקוז', 'ת"י 1515.3 — מרפסות חייבות איטום מלא עם שיפוע לניקוז', true, 'medium');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'איטום — חדרים רטובים', '**נזילה סביב חדירת צנרת בגג** — איטום לקוי סביב חדירות צנרת, אוורור או כבלים בגג. נקודות חדירה הן מוקדי כשל נפוצים לחדירת מים.. המלצה: התקנת שרוול איטום (boot) תקני סביב כל חדירה, הלחמה ליריעה הראשית בחפיפה של 15 ס"מ לפחות, ואטימה עליונה בחומר אלסטומרי. עלות משוערת: ₪350-₪800 (ליחידה)', '**נזילה סביב חדירת צנרת בגג** — איטום לקוי סביב חדירות צנרת, אוורור או כבלים בגג. נקודות חדירה הן מוקדי כשל נפוצים לחדירת מים.. המלצה: התקנת שרוול איטום (boot) תקני סביב כל חדירה, הלחמה ליריעה הראשית בחפיפה של 15 ס"מ לפחות, ואטימה עליונה בחומר אלסטומרי. עלות משוערת: ₪350-₪800 (ליחידה)', 'ת"י 931 — כל חדירה דרך מערכת האיטום חייבת איטום ייעודי בשרוול איטום או פלנג'' עם חפיפה ליריעה הראשית', 'ת"י 931 — כל חדירה דרך מערכת האיטום חייבת איטום ייעודי בשרוול איטום או פלנג'' עם חפיפה ליריעה הראשית', true, 'medium');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'איטום — חדרים רטובים', '**חוסר איטום חדר רחצה — רצפה** — לא בוצע איטום מתחת לריצוף חדר הרחצה/מקלחת. מים חודרים דרך המרצפות ופגעים לתקרה ולקירות הדירה מתחת.. המלצה: הסרת ריצוף קיים, ביצוע איטום מלא בציפוי אלסטי דו-רכיבי עם כיפוף 15 ס"מ על הקירות, ריצוף מחדש. עלות משוערת: ₪300-₪500 (למ"ר)', '**חוסר איטום חדר רחצה — רצפה** — לא בוצע איטום מתחת לריצוף חדר הרחצה/מקלחת. מים חודרים דרך המרצפות ופגעים לתקרה ולקירות הדירה מתחת.. המלצה: הסרת ריצוף קיים, ביצוע איטום מלא בציפוי אלסטי דו-רכיבי עם כיפוף 15 ס"מ על הקירות, ריצוף מחדש. עלות משוערת: ₪300-₪500 (למ"ר)', 'ת"י 1752 — רצפת חדר רחצה ומקלחת חייבת איטום מלא בציפוי אלסטי או יריעה, כולל כיפופים על הקירות', 'ת"י 1752 — רצפת חדר רחצה ומקלחת חייבת איטום מלא בציפוי אלסטי או יריעה, כולל כיפופים על הקירות', true, 'critical');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'איטום — חדרים רטובים', '**כיפוף איטום לא מספיק בקירות חדר רחצה** — איטום רצפת חדר הרחצה לא עולה בכיפוף על הקירות בגובה מספיק (פחות מ-10 ס"מ ברצפה, פחות מ-180 ס"מ באזור המקלחת).. המלצה: הסרת אריחי קיר באזורים הנדרשים, ביצוע כיפוף איטום לגובה תקני, ואריחוי מחדש. עלות משוערת: ₪2000-₪5000 (ליחידה)', '**כיפוף איטום לא מספיק בקירות חדר רחצה** — איטום רצפת חדר הרחצה לא עולה בכיפוף על הקירות בגובה מספיק (פחות מ-10 ס"מ ברצפה, פחות מ-180 ס"מ באזור המקלחת).. המלצה: הסרת אריחי קיר באזורים הנדרשים, ביצוע כיפוף איטום לגובה תקני, ואריחוי מחדש. עלות משוערת: ₪2000-₪5000 (ליחידה)', 'ת"י 1752 — כיפוף איטום: מינימום 10 ס"מ על קירות כלליים, 180 ס"מ באזור מקלחת, גובה מלא מאחורי אמבטיה', 'ת"י 1752 — כיפוף איטום: מינימום 10 ס"מ על קירות כלליים, 180 ס"מ באזור מקלחת, גובה מלא מאחורי אמבטיה', true, 'medium');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'איטום — חדרים רטובים', '**אטימה לקויה סביב ניקוז רצפתי בחדר רחצה** — מפגש האיטום עם הניקוז הרצפתי (נקז רצפה) לא בוצע כראוי — חסר טבעת איטום או חפיפה לא מספיקה. נקודת חדירת מים תכופה.. המלצה: החלפת הנקז הרצפתי והתקנת טבעת איטום תקנית עם חפיפה מלאה למערכת האיטום. עלות משוערת: ₪800-₪1800 (ליחידה)', '**אטימה לקויה סביב ניקוז רצפתי בחדר רחצה** — מפגש האיטום עם הניקוז הרצפתי (נקז רצפה) לא בוצע כראוי — חסר טבעת איטום או חפיפה לא מספיקה. נקודת חדירת מים תכופה.. המלצה: החלפת הנקז הרצפתי והתקנת טבעת איטום תקנית עם חפיפה מלאה למערכת האיטום. עלות משוערת: ₪800-₪1800 (ליחידה)', 'ת"י 1752 — ניקוז רצפתי חייב טבעת איטום ייעודית עם חפיפה למערכת האיטום הרצפתית', 'ת"י 1752 — ניקוז רצפתי חייב טבעת איטום ייעודית עם חפיפה למערכת האיטום הרצפתית', true, 'medium');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'איטום — חדרים רטובים', '**חוסר איטום רצפת מרתף** — רצפת המרתף ללא מערכת איטום נגד עליית מי תהום. מים עולים דרך הרצפה וגורמים לרטיבות מתמדת.. המלצה: ביצוע איטום פנימי בציפוי קריסטלי (crystalline) או ממברנה ביטומנית, עם מערכת ניקוז תת-רצפתי למשאבה. עלות משוערת: ₪200-₪350 (למ"ר)', '**חוסר איטום רצפת מרתף** — רצפת המרתף ללא מערכת איטום נגד עליית מי תהום. מים עולים דרך הרצפה וגורמים לרטיבות מתמדת.. המלצה: ביצוע איטום פנימי בציפוי קריסטלי (crystalline) או ממברנה ביטומנית, עם מערכת ניקוז תת-רצפתי למשאבה. עלות משוערת: ₪200-₪350 (למ"ר)', 'ת"י 931 — רצפות מתחת למפלס הקרקע חייבות איטום נגד לחות עולה, כולל מחסום אדים', 'ת"י 931 — רצפות מתחת למפלס הקרקע חייבות איטום נגד לחות עולה, כולל מחסום אדים', true, 'medium');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'איטום — חדרים רטובים', '**חוסר איטום קיר תומך (קיר גבי)** — קיר תומך במגע עם קרקע ללא איטום חיצוני. לחות ומים חודרים דרך הקיר וגורמים לרטיבות, עובש ופגיעה במבנה.. המלצה: חפירה מצד הקרקע, ניקוי הקיר, מריחת פריימר ביטומני, הדבקת יריעת איטום, התקנת צנרת ניקוז ומילוי בחומר מנקז. עלות משוערת: ₪600-₪1200 (למ"א)', '**חוסר איטום קיר תומך (קיר גבי)** — קיר תומך במגע עם קרקע ללא איטום חיצוני. לחות ומים חודרים דרך הקיר וגורמים לרטיבות, עובש ופגיעה במבנה.. המלצה: חפירה מצד הקרקע, ניקוי הקיר, מריחת פריימר ביטומני, הדבקת יריעת איטום, התקנת צנרת ניקוז ומילוי בחומר מנקז. עלות משוערת: ₪600-₪1200 (למ"א)', 'ת"י 931 — קירות תומכים במגע עם קרקע חייבים איטום חיצוני מלא ומערכת ניקוז', 'ת"י 931 — קירות תומכים במגע עם קרקע חייבים איטום חיצוני מלא ומערכת ניקוז', true, 'medium');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'איטום — חדרים רטובים', '**חוסר אטימה באדן חלון חיצוני** — אדן חלון חיצוני ללא שיפוע כלפי חוץ, ללא שפה מנטפת (drip edge), או ללא אטימה בין האדן למסגרת. מים מצטברים ונכנסים דרך מפגש חלון-קיר.. המלצה: התקנת אדן עם שיפוע מינימלי 3% כלפי חוץ, שפה מנטפת, ואטימה בסיליקון סביב מסגרת החלון. עלות משוערת: ₪250-₪600 (ליחידה)', '**חוסר אטימה באדן חלון חיצוני** — אדן חלון חיצוני ללא שיפוע כלפי חוץ, ללא שפה מנטפת (drip edge), או ללא אטימה בין האדן למסגרת. מים מצטברים ונכנסים דרך מפגש חלון-קיר.. המלצה: התקנת אדן עם שיפוע מינימלי 3% כלפי חוץ, שפה מנטפת, ואטימה בסיליקון סביב מסגרת החלון. עלות משוערת: ₪250-₪600 (ליחידה)', 'ת"י 931 — אדני חלונות חיצוניים חייבים שיפוע כלפי חוץ ושפה מנטפת למניעת נזילת מים אל הקיר', 'ת"י 931 — אדני חלונות חיצוניים חייבים שיפוע כלפי חוץ ושפה מנטפת למניעת נזילת מים אל הקיר', true, 'medium');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'איטום — חדרים רטובים', '**אטימה לקויה סביב מסגרת חלון** — חומר האטימה (סיליקון/פוליאוריתן) סביב מסגרת החלון סדוק, מנותק או חסר. רוח ומים חודרים דרך הרווח שבין המסגרת לקיר.. המלצה: הסרת אטימה ישנה, ניקוי המשטחים, מילוי קצף פוליאוריתן בחלל, וגמר באטם סיליקון או פוליאוריתן UV-resistant. עלות משוערת: ₪100-₪250 (ליחידה)', '**אטימה לקויה סביב מסגרת חלון** — חומר האטימה (סיליקון/פוליאוריתן) סביב מסגרת החלון סדוק, מנותק או חסר. רוח ומים חודרים דרך הרווח שבין המסגרת לקיר.. המלצה: הסרת אטימה ישנה, ניקוי המשטחים, מילוי קצף פוליאוריתן בחלל, וגמר באטם סיליקון או פוליאוריתן UV-resistant. עלות משוערת: ₪100-₪250 (ליחידה)', 'ת"י 931 — מפגש מסגרת חלון-קיר חייב אטימה מלאה בחומר אלסטי עמיד בתנאי חוץ', 'ת"י 931 — מפגש מסגרת חלון-קיר חייב אטימה מלאה בחומר אלסטי עמיד בתנאי חוץ', true, 'medium');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'איטום — חדרים רטובים', '**חוסר איטום בטון חשוף בתקרת חניה** — תקרת חניה תת-קרקעית ללא מערכת איטום. מים חודרים מהגינה או הכביש מעל ופוגעים בברזל הזיון ובמבנה הבטון.. המלצה: ביצוע מערכת איטום על תקרת החניה: פריימר + יריעה ביטומנית דו-שכבתית + שכבת הגנה + ניקוז. עלות משוערת: ₪180-₪300 (למ"ר)', '**חוסר איטום בטון חשוף בתקרת חניה** — תקרת חניה תת-קרקעית ללא מערכת איטום. מים חודרים מהגינה או הכביש מעל ופוגעים בברזל הזיון ובמבנה הבטון.. המלצה: ביצוע מערכת איטום על תקרת החניה: פריימר + יריעה ביטומנית דו-שכבתית + שכבת הגנה + ניקוז. עלות משוערת: ₪180-₪300 (למ"ר)', 'ת"י 931 — תקרות מתחת למפלס קרקע או חשופות לגשם חייבות מערכת איטום מלאה', 'ת"י 931 — תקרות מתחת למפלס קרקע או חשופות לגשם חייבות מערכת איטום מלאה', true, 'critical');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'איטום — חדרים רטובים', '**אטימה חסרה בין אמבטיה/מקלחון לקיר** — חסר חומר אטימה (סיליקון) בין אמבטיה או מקלחון לקיר המרוצף. מים חודרים לרווח וגורמים לרטיבות מאחורי האמבטיה.. המלצה: ניקוי המשטחים, התקנת סרט אטימה או מילוי בסיליקון סניטרי אנטי-עובש. עלות משוערת: ₪150-₪400 (ליחידה)', '**אטימה חסרה בין אמבטיה/מקלחון לקיר** — חסר חומר אטימה (סיליקון) בין אמבטיה או מקלחון לקיר המרוצף. מים חודרים לרווח וגורמים לרטיבות מאחורי האמבטיה.. המלצה: ניקוי המשטחים, התקנת סרט אטימה או מילוי בסיליקון סניטרי אנטי-עובש. עלות משוערת: ₪150-₪400 (ליחידה)', 'ת"י 1752 — מפגשי כלים סניטריים עם קירות וריצוף חייבים אטימה מלאה בחומר אלסטי עמיד במים', 'ת"י 1752 — מפגשי כלים סניטריים עם קירות וריצוף חייבים אטימה מלאה בחומר אלסטי עמיד במים', true, 'medium');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'איטום — חדרים רטובים', '**חוסר איטום מתחת לאמבטיה** — שטח הרצפה מתחת לאמבטיה לא אוטם. במקרה של נזילה מהאמבטיה או מהצנרת מתחתיה, מים חודרים ישירות לתקרת הדירה מתחת.. המלצה: הסרת האמבטיה, ביצוע איטום רצפתי מלא כולל מתחת לאמבטיה, והתקנה מחדש. עלות משוערת: ₪3000-₪7000 (ליחידה)', '**חוסר איטום מתחת לאמבטיה** — שטח הרצפה מתחת לאמבטיה לא אוטם. במקרה של נזילה מהאמבטיה או מהצנרת מתחתיה, מים חודרים ישירות לתקרת הדירה מתחת.. המלצה: הסרת האמבטיה, ביצוע איטום רצפתי מלא כולל מתחת לאמבטיה, והתקנה מחדש. עלות משוערת: ₪3000-₪7000 (ליחידה)', 'ת"י 1752 — כל שטח רצפת חדר הרחצה חייב איטום, כולל השטח מתחת לאמבטיה', 'ת"י 1752 — כל שטח רצפת חדר הרחצה חייב איטום, כולל השטח מתחת לאמבטיה', true, 'medium');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'איטום — חדרים רטובים', '**סיליקון חסר / פגום בחדר רחצה** — סיליקון חסר, סדוק או מתקלף בפינות חדר רחצה, מקלחת, אמבטיה או כיור.. המלצה: הסרת סיליקון ישן, ניקוי, מילוי סיליקון חדש. עלות משוערת: ₪150-₪400 (ליחידה)', '**סיליקון חסר / פגום בחדר רחצה** — סיליקון חסר, סדוק או מתקלף בפינות חדר רחצה, מקלחת, אמבטיה או כיור.. המלצה: הסרת סיליקון ישן, ניקוי, מילוי סיליקון חדש. עלות משוערת: ₪150-₪400 (ליחידה)', NULL, NULL, true, 'medium');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'איטום — חדרים רטובים', '**מחסן — רטיבות / איטום** — רטיבות או סימני מים במחסן.. המלצה: איטום מחסן, ניקוז, שיפור אוורור. עלות משוערת: ₪500-₪2000 (ליחידה)', '**מחסן — רטיבות / איטום** — רטיבות או סימני מים במחסן.. המלצה: איטום מחסן, ניקוז, שיפור אוורור. עלות משוערת: ₪500-₪2000 (ליחידה)', NULL, NULL, true, 'medium');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'רטיבות ועובש', '**רטיבות בקירות מרתף — חדירה מהקרקע** — כתמי רטיבות, עובש או פריחת מלח (אפלורסנציה) על קירות המרתף. מעיד על חוסר איטום חיצוני או כשל באיטום הקיים נגד לחץ מי תהום.. המלצה: חפירה חיצונית עד ליסוד, ניקוי ותיקון הקיר, ביצוע איטום חיצוני בשכבת ביטומן + יריעה, ומילוי בחזרה עם שכבת סינון. עלות משוערת: ₪800-₪1500 (למ"א)', '**רטיבות בקירות מרתף — חדירה מהקרקע** — כתמי רטיבות, עובש או פריחת מלח (אפלורסנציה) על קירות המרתף. מעיד על חוסר איטום חיצוני או כשל באיטום הקיים נגד לחץ מי תהום.. המלצה: חפירה חיצונית עד ליסוד, ניקוי ותיקון הקיר, ביצוע איטום חיצוני בשכבת ביטומן + יריעה, ומילוי בחזרה עם שכבת סינון. עלות משוערת: ₪800-₪1500 (למ"א)', 'ת"י 931 — קירות מרתף מתחת למפלס הקרקע חייבים איטום חיצוני מלא נגד לחות ולחץ מים', 'ת"י 931 — קירות מרתף מתחת למפלס הקרקע חייבים איטום חיצוני מלא נגד לחות ולחץ מים', true, 'critical');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'רטיבות ועובש', '**חוסר ניקוז בגב קיר תומך** — קיר תומך ללא מערכת ניקוז מאחוריו (צנרת ניקוז, חומר מנקז, או פתחי ניקוז). לחץ הידרוסטטי על הקיר גורם לחדירת מים ועלול לפגוע ביציבותו.. המלצה: התקנת מערכת ניקוז: צנרת מנקזת מחוררת עטופה בגיאוטקסטיל, שכבת חצץ, וחיבור לתשתית ניקוז. עלות משוערת: ₪400-₪800 (למ"א)', '**חוסר ניקוז בגב קיר תומך** — קיר תומך ללא מערכת ניקוז מאחוריו (צנרת ניקוז, חומר מנקז, או פתחי ניקוז). לחץ הידרוסטטי על הקיר גורם לחדירת מים ועלול לפגוע ביציבותו.. המלצה: התקנת מערכת ניקוז: צנרת מנקזת מחוררת עטופה בגיאוטקסטיל, שכבת חצץ, וחיבור לתשתית ניקוז. עלות משוערת: ₪400-₪800 (למ"א)', 'ת"י 931 — קיר תומך חייב מערכת ניקוז כולל צנרת מנקזת, שכבת חצץ מנקז, ופתחי ניקוז (weep holes)', 'ת"י 931 — קיר תומך חייב מערכת ניקוז כולל צנרת מנקזת, שכבת חצץ מנקז, ופתחי ניקוז (weep holes)', true, 'medium');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'רטיבות ועובש', '**רטיבות עולה בקירות (רטיבות קפילרית)** — רטיבות עולה מהיסוד לקירות בקומת הקרקע (rising damp). כתמי רטיבות, פריחת מלח וטיח מתקלף בחלק התחתון של הקירות. מעיד על חוסר מחסום רטיבות (DPC).. המלצה: הזרקת חומר חוסם רטיבות (cream/gel silane) בקידוחים בבסיס הקיר, ניקוי וחידוש טיח במלט עמיד ברטיבות. עלות משוערת: ₪150-₪350 (למ"א)', '**רטיבות עולה בקירות (רטיבות קפילרית)** — רטיבות עולה מהיסוד לקירות בקומת הקרקע (rising damp). כתמי רטיבות, פריחת מלח וטיח מתקלף בחלק התחתון של הקירות. מעיד על חוסר מחסום רטיבות (DPC).. המלצה: הזרקת חומר חוסם רטיבות (cream/gel silane) בקידוחים בבסיס הקיר, ניקוי וחידוש טיח במלט עמיד ברטיבות. עלות משוערת: ₪150-₪350 (למ"א)', 'ת"י 931 — חובה למנוע מעבר רטיבות מהיסוד לקירות באמצעות מחסום רטיבות (DPC) ביסוד', 'ת"י 931 — חובה למנוע מעבר רטיבות מהיסוד לקירות באמצעות מחסום רטיבות (DPC) ביסוד', true, 'medium');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'רטיבות ועובש', '**עובש על קירות ותקרה כתוצאה מעיבוי** — כתמי עובש שחורים/ירוקים על קירות חיצוניים ותקרות, בעיקר בפינות ומאחורי רהיטים. כתוצאה מגשרים תרמיים, בידוד חסר ואוורור לקוי.. המלצה: טיפול בעובש בחומר אנטי-פטרייתי, שיפור בידוד תרמי חיצוני, התקנת מערכת אוורור מכני, ובדיקת גשרים תרמיים. עלות משוערת: ₪500-₪3000 (ליחידה)', '**עובש על קירות ותקרה כתוצאה מעיבוי** — כתמי עובש שחורים/ירוקים על קירות חיצוניים ותקרות, בעיקר בפינות ומאחורי רהיטים. כתוצאה מגשרים תרמיים, בידוד חסר ואוורור לקוי.. המלצה: טיפול בעובש בחומר אנטי-פטרייתי, שיפור בידוד תרמי חיצוני, התקנת מערכת אוורור מכני, ובדיקת גשרים תרמיים. עלות משוערת: ₪500-₪3000 (ליחידה)', NULL, NULL, true, 'medium');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'רטיבות ועובש', '**גשר תרמי בתקרת גג — רטיבות עיבוי** — גשר תרמי באזור מפגש תקרה-קיר חיצוני (thermal bridge) גורם לטמפרטורה נמוכה של המשטח הפנימי ולעיבוי מים. מתבטא בעובש ורטיבות בפינות העליונות.. המלצה: שיפור בידוד תרמי באזור הגשר התרמי, הוספת שכבת בידוד פנימית או חיצונית, ושיפור אוורור. עלות משוערת: ₪2000-₪8000 (ליחידה)', '**גשר תרמי בתקרת גג — רטיבות עיבוי** — גשר תרמי באזור מפגש תקרה-קיר חיצוני (thermal bridge) גורם לטמפרטורה נמוכה של המשטח הפנימי ולעיבוי מים. מתבטא בעובש ורטיבות בפינות העליונות.. המלצה: שיפור בידוד תרמי באזור הגשר התרמי, הוספת שכבת בידוד פנימית או חיצונית, ושיפור אוורור. עלות משוערת: ₪2000-₪8000 (ליחידה)', NULL, NULL, true, 'medium');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'רטיבות ועובש', '**חדירת מים דרך סדקים במבנה הבטון** — סדקים במבנה הבטון (תקרה, קורות, קירות) מאפשרים חדירת מים. הסדקים עשויים להצביע על בעיה מבנית בנוסף לבעיית האיטום.. המלצה: הזרקת חומר אפוקסי או פוליאוריתן לסדקים, בדיקה מבנית של הסדקים על ידי מהנדס, ושיקום האיטום. עלות משוערת: ₪200-₪600 (למ"א)', '**חדירת מים דרך סדקים במבנה הבטון** — סדקים במבנה הבטון (תקרה, קורות, קירות) מאפשרים חדירת מים. הסדקים עשויים להצביע על בעיה מבנית בנוסף לבעיית האיטום.. המלצה: הזרקת חומר אפוקסי או פוליאוריתן לסדקים, בדיקה מבנית של הסדקים על ידי מהנדס, ושיקום האיטום. עלות משוערת: ₪200-₪600 (למ"א)', 'ת"י 931 — מבנה הבטון חייב להיות אטום, סדקים מעל 0.3 מ"מ דורשים טיפול לשיקום האטימות', 'ת"י 931 — מבנה הבטון חייב להיות אטום, סדקים מעל 0.3 מ"מ דורשים טיפול לשיקום האטימות', true, 'medium');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'רטיבות ועובש', '**נזילת מים מצנרת מעבר בתקרה/רצפה** — צנרת מים/ביוב חוצה רצפה או תקרה ללא אטימה סביב המעבר. מים (מנזילה או עיבוי) זולגים דרך הפתח.. המלצה: התקנת שרוול מעבר (sleeve) עם אטם גומי או מילוי בחומר אטימה חסין אש וגמיש. עלות משוערת: ₪200-₪500 (ליחידה)', '**נזילת מים מצנרת מעבר בתקרה/רצפה** — צנרת מים/ביוב חוצה רצפה או תקרה ללא אטימה סביב המעבר. מים (מנזילה או עיבוי) זולגים דרך הפתח.. המלצה: התקנת שרוול מעבר (sleeve) עם אטם גומי או מילוי בחומר אטימה חסין אש וגמיש. עלות משוערת: ₪200-₪500 (ליחידה)', 'ת"י 931 — כל מעבר צנרת דרך אלמנט בטון חייב אטימה ייעודית באמצעות שרוול ואטם גמיש', 'ת"י 931 — כל מעבר צנרת דרך אלמנט בטון חייב אטימה ייעודית באמצעות שרוול ואטם גמיש', true, 'medium');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'רטיבות ועובש', '**רטיבות בתקרה / קיר** — סימני רטיבות בתקרה או קיר — כתמים, התנפחות צבע, עובש.. המלצה: איתור מקור רטיבות, תיקון איטום, ייבוש וצביעה. עלות משוערת: ₪500-₪3000 (ליחידה)', '**רטיבות בתקרה / קיר** — סימני רטיבות בתקרה או קיר — כתמים, התנפחות צבע, עובש.. המלצה: איתור מקור רטיבות, תיקון איטום, ייבוש וצביעה. עלות משוערת: ₪500-₪3000 (ליחידה)', 'ת"י 1515.3 — איטום חייב למנוע חדירת מים לחלל הדירה', 'ת"י 1515.3 — איטום חייב למנוע חדירת מים לחלל הדירה', true, 'medium');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'רטיבות ועובש', '**עובש בפינות / תקרה** — עובש שחור או ירוק בפינות חדרים, תקרות, או סביבת חלונות.. המלצה: טיפול בעובש, בדיקת מקור רטיבות, שיפור אוורור. עלות משוערת: ₪200-₪800 (ליחידה)', '**עובש בפינות / תקרה** — עובש שחור או ירוק בפינות חדרים, תקרות, או סביבת חלונות.. המלצה: טיפול בעובש, בדיקת מקור רטיבות, שיפור אוורור. עלות משוערת: ₪200-₪800 (ליחידה)', NULL, NULL, true, 'medium');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'כיבוי אש', '**ספרינקלר חסר או לא מותקן בחדר מדרגות** — ראש ספרינקלר לא הותקן בחדר מדרגות או בשטח ציבורי כנדרש בתכניות כיבוי האש המאושרות. העדר ספרינקלר מפחית את יכולת הכיבוי האוטומטי במקרה שריפה.. המלצה: התקנת ראש ספרינקלר מאושר בהתאם לתכנית כיבוי האש, כולל חיבור לצנרת הקיימת ובדיקת לחץ. עלות משוערת: ₪350-₪800 (ליחידה)', '**ספרינקלר חסר או לא מותקן בחדר מדרגות** — ראש ספרינקלר לא הותקן בחדר מדרגות או בשטח ציבורי כנדרש בתכניות כיבוי האש המאושרות. העדר ספרינקלר מפחית את יכולת הכיבוי האוטומטי במקרה שריפה.. המלצה: התקנת ראש ספרינקלר מאושר בהתאם לתכנית כיבוי האש, כולל חיבור לצנרת הקיימת ובדיקת לחץ. עלות משוערת: ₪350-₪800 (ליחידה)', 'ת"י 1596 — מערכת ספרינקלרים אוטומטית נדרשת בבניין מגורים מעל קומה מסוימת בהתאם לתקנות כיבוי אש, כולל כיסוי מלא בשטחים ציבוריים', 'ת"י 1596 — מערכת ספרינקלרים אוטומטית נדרשת בבניין מגורים מעל קומה מסוימת בהתאם לתקנות כיבוי אש, כולל כיסוי מלא בשטחים ציבוריים', true, 'critical');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'כיבוי אש', '**ספרינקלר צבוע או חסום** — ראש ספרינקלר נצבע במהלך עבודות צביעה או חסום על ידי חפצים/מדפים. צביעה על הספרינקלר עלולה למנוע את פעולתו בעת שריפה.. המלצה: החלפת ראש הספרינקלר הצבוע בחדש מאותו סוג ודירוג טמפרטורה, והסרת כל חסימה. עלות משוערת: ₪200-₪500 (ליחידה)', '**ספרינקלר צבוע או חסום** — ראש ספרינקלר נצבע במהלך עבודות צביעה או חסום על ידי חפצים/מדפים. צביעה על הספרינקלר עלולה למנוע את פעולתו בעת שריפה.. המלצה: החלפת ראש הספרינקלר הצבוע בחדש מאותו סוג ודירוג טמפרטורה, והסרת כל חסימה. עלות משוערת: ₪200-₪500 (ליחידה)', 'ת"י 1596 — חל איסור מוחלט לצבוע או לחסום ראשי ספרינקלרים; יש לשמור מרחק חופשי של 50 ס"מ לפחות מכל כיוון', 'ת"י 1596 — חל איסור מוחלט לצבוע או לחסום ראשי ספרינקלרים; יש לשמור מרחק חופשי של 50 ס"מ לפחות מכל כיוון', true, 'critical');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'כיבוי אש', '**גלגלון כיבוי אש לא תקין או חסר** — גלגלון כיבוי אש בחדר מדרגות לא פועל, צינור קרוע, ברז תקוע, או חסר לחלוטין. הגלגלון הוא אמצעי כיבוי ראשוני לדיירים.. המלצה: החלפת גלגלון כיבוי אש פגום בגלגלון חדש תקני, כולל צינור, ברז, וזרנוק, ובדיקת לחץ מים. עלות משוערת: ₪1200-₪2500 (ליחידה)', '**גלגלון כיבוי אש לא תקין או חסר** — גלגלון כיבוי אש בחדר מדרגות לא פועל, צינור קרוע, ברז תקוע, או חסר לחלוטין. הגלגלון הוא אמצעי כיבוי ראשוני לדיירים.. המלצה: החלפת גלגלון כיבוי אש פגום בגלגלון חדש תקני, כולל צינור, ברז, וזרנוק, ובדיקת לחץ מים. עלות משוערת: ₪1200-₪2500 (ליחידה)', 'ת"י 5765 — גלגלון כיבוי אש חייב להיות תקין, נגיש, עם צינור באורך מספק (לפחות 30 מטר כולל סילון), ולעבור בדיקה שנתית', 'ת"י 5765 — גלגלון כיבוי אש חייב להיות תקין, נגיש, עם צינור באורך מספק (לפחות 30 מטר כולל סילון), ולעבור בדיקה שנתית', true, 'critical');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'כיבוי אש', '**ארון כיבוי אש פגום או לא נגיש** — ארון כיבוי אש שבור, חלוד, דלת לא נפתחת, או חסום על ידי חפצים. חוסר נגישות לארון מונע שימוש באמצעי הכיבוי בזמן חירום.. המלצה: תיקון או החלפת ארון כיבוי אש, החלפת דלת שבורה, הסרת חסימות, וסימון מחדש בהתאם לתקן. עלות משוערת: ₪600-₪1500 (ליחידה)', '**ארון כיבוי אש פגום או לא נגיש** — ארון כיבוי אש שבור, חלוד, דלת לא נפתחת, או חסום על ידי חפצים. חוסר נגישות לארון מונע שימוש באמצעי הכיבוי בזמן חירום.. המלצה: תיקון או החלפת ארון כיבוי אש, החלפת דלת שבורה, הסרת חסימות, וסימון מחדש בהתאם לתקן. עלות משוערת: ₪600-₪1500 (ליחידה)', 'ת"י 5765 — ארון כיבוי אש חייב להיות נגיש, מסומן, דלתו חייבת להיפתח ללא מפתח מיוחד, ותכולתו חייבת להיות תקינה', 'ת"י 5765 — ארון כיבוי אש חייב להיות נגיש, מסומן, דלתו חייבת להיפתח ללא מפתח מיוחד, ותכולתו חייבת להיות תקינה', true, 'medium');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'כיבוי אש', '**מטף כיבוי אש חסר או פג תוקף** — מטף כיבוי אש לא מותקן בשטח ציבורי כנדרש, או שתוקפו פג ולא עבר בדיקה שנתית. מטף ללא בדיקה עשוי לא לפעול בעת הצורך.. המלצה: התקנת מטף כיבוי אש חדש בתוקף או שליחת המטף הקיים לבדיקה ומילוי חוזר, כולל תיוג ובדיקת נגישות. עלות משוערת: ₪150-₪400 (ליחידה)', '**מטף כיבוי אש חסר או פג תוקף** — מטף כיבוי אש לא מותקן בשטח ציבורי כנדרש, או שתוקפו פג ולא עבר בדיקה שנתית. מטף ללא בדיקה עשוי לא לפעול בעת הצורך.. המלצה: התקנת מטף כיבוי אש חדש בתוקף או שליחת המטף הקיים לבדיקה ומילוי חוזר, כולל תיוג ובדיקת נגישות. עלות משוערת: ₪150-₪400 (ליחידה)', 'ת"י 129 — מטפי כיבוי אש חייבים לעבור בדיקה שנתית על ידי בודק מוסמך, לשאת תווית בדיקה בתוקף, ולהיות מותקנים בגובה ובמיקום נגישים', 'ת"י 129 — מטפי כיבוי אש חייבים לעבור בדיקה שנתית על ידי בודק מוסמך, לשאת תווית בדיקה בתוקף, ולהיות מותקנים בגובה ובמיקום נגישים', true, 'medium');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'כיבוי אש', '**דלת אש חסרה או לא תקנית** — דלת אש בחדר מדרגות או במעבר חסרה, הוחלפה בדלת רגילה, או שאינה עומדת בדירוג עמידות אש נדרש. דלת אש מהווה מחסום קריטי למניעת התפשטות עשן ואש.. המלצה: התקנת דלת אש מאושרת בדירוג EI60 לפחות, כולל סוגר אוטומטי, אטם אש מתנפח, ומשקוף מתאים. עלות משוערת: ₪3500-₪7000 (ליחידה)', '**דלת אש חסרה או לא תקנית** — דלת אש בחדר מדרגות או במעבר חסרה, הוחלפה בדלת רגילה, או שאינה עומדת בדירוג עמידות אש נדרש. דלת אש מהווה מחסום קריטי למניעת התפשטות עשן ואש.. המלצה: התקנת דלת אש מאושרת בדירוג EI60 לפחות, כולל סוגר אוטומטי, אטם אש מתנפח, ומשקוף מתאים. עלות משוערת: ₪3500-₪7000 (ליחידה)', 'ת"י 1220 — דלת אש חייבת לעמוד בדירוג עמידות אש של 60 דקות לפחות (EI60), לכלול סוגר אוטומטי, ולהיות מסומנת בתווית עמידות אש', 'ת"י 1220 — דלת אש חייבת לעמוד בדירוג עמידות אש של 60 דקות לפחות (EI60), לכלול סוגר אוטומטי, ולהיות מסומנת בתווית עמידות אש', true, 'critical');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'כיבוי אש', '**סוגר אוטומטי בדלת אש לא פועל** — סוגר הדלת האוטומטי (door closer) בדלת אש לא פועל, שבור, או הוסר. ללא סוגר תקין, הדלת נשארת פתוחה ואינה מהווה מחסום אש.. המלצה: החלפת סוגר אוטומטי פגום בסוגר חדש בהתאם למשקל ולגודל הדלת, כיוון מהירות סגירה. עלות משוערת: ₪400-₪900 (ליחידה)', '**סוגר אוטומטי בדלת אש לא פועל** — סוגר הדלת האוטומטי (door closer) בדלת אש לא פועל, שבור, או הוסר. ללא סוגר תקין, הדלת נשארת פתוחה ואינה מהווה מחסום אש.. המלצה: החלפת סוגר אוטומטי פגום בסוגר חדש בהתאם למשקל ולגודל הדלת, כיוון מהירות סגירה. עלות משוערת: ₪400-₪900 (ליחידה)', 'ת"י 1220 — כל דלת אש חייבת להיות מצוידת בסוגר אוטומטי תקין המבטיח סגירה מלאה של הדלת לאחר כל פתיחה', 'ת"י 1220 — כל דלת אש חייבת להיות מצוידת בסוגר אוטומטי תקין המבטיח סגירה מלאה של הדלת לאחר כל פתיחה', true, 'medium');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'כיבוי אש', '**אטם אש מתנפח חסר בדלת אש** — אטם אש מתנפח (intumescent strip) חסר או פגום בדלת אש. האטם מתנפח בחום ואוטם את המרווח בין הדלת למשקוף, מונע מעבר עשן ואש.. המלצה: התקנת אטם אש מתנפח חדש בתעלת האטם בהיקף הדלת, כולל אטם עשן. עלות משוערת: ₪250-₪600 (ליחידה)', '**אטם אש מתנפח חסר בדלת אש** — אטם אש מתנפח (intumescent strip) חסר או פגום בדלת אש. האטם מתנפח בחום ואוטם את המרווח בין הדלת למשקוף, מונע מעבר עשן ואש.. המלצה: התקנת אטם אש מתנפח חדש בתעלת האטם בהיקף הדלת, כולל אטם עשן. עלות משוערת: ₪250-₪600 (ליחידה)', 'ת"י 1220 — דלת אש חייבת לכלול אטם אש מתנפח בהיקף הדלת להבטחת אטימות לעשן ולאש', 'ת"י 1220 — דלת אש חייבת לכלול אטם אש מתנפח בהיקף הדלת להבטחת אטימות לעשן ולאש', true, 'medium');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'כיבוי אש', '**גלאי עשן חסר או לא פועל בשטח ציבורי** — גלאי עשן לא מותקן בחדר מדרגות, לובי, או חניון כנדרש, או שהגלאי מותקן אך אינו פעיל (נורית לא דולקת, סוללה ריקה).. המלצה: התקנת גלאי עשן אופטי או חיווט למערכת גילוי אש מרכזית, בדיקת תקינות וחיבור ללוח בקרה. עלות משוערת: ₪200-₪600 (ליחידה)', '**גלאי עשן חסר או לא פועל בשטח ציבורי** — גלאי עשן לא מותקן בחדר מדרגות, לובי, או חניון כנדרש, או שהגלאי מותקן אך אינו פעיל (נורית לא דולקת, סוללה ריקה).. המלצה: התקנת גלאי עשן אופטי או חיווט למערכת גילוי אש מרכזית, בדיקת תקינות וחיבור ללוח בקרה. עלות משוערת: ₪200-₪600 (ליחידה)', 'בהתאם לתקנות כיבוי אש, נדרשת מערכת גילוי אש בשטחים ציבוריים בבניין מגורים הכולל יותר מ-4 קומות', 'בהתאם לתקנות כיבוי אש, נדרשת מערכת גילוי אש בשטחים ציבוריים בבניין מגורים הכולל יותר מ-4 קומות', true, 'critical');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'כיבוי אש', '**לוח בקרת אש לא תקין או ללא חשמל** — לוח בקרת מערכת גילוי אש מציג תקלה, מנותק מחשמל, או שסוללת הגיבוי ריקה. לוח לא תקין פירושו שמערכת גילוי האש כולה לא פעילה.. המלצה: תיקון לוח בקרה, החלפת סוללת גיבוי, בדיקת חיבורי גלאים ואזעקות, וביצוע בדיקת מערכת מלאה. עלות משוערת: ₪800-₪3000 (ליחידה)', '**לוח בקרת אש לא תקין או ללא חשמל** — לוח בקרת מערכת גילוי אש מציג תקלה, מנותק מחשמל, או שסוללת הגיבוי ריקה. לוח לא תקין פירושו שמערכת גילוי האש כולה לא פעילה.. המלצה: תיקון לוח בקרה, החלפת סוללת גיבוי, בדיקת חיבורי גלאים ואזעקות, וביצוע בדיקת מערכת מלאה. עלות משוערת: ₪800-₪3000 (ליחידה)', 'לוח בקרת אש חייב להיות פעיל 24/7, כולל גיבוי סוללה ל-24 שעות, ולעבור בדיקה תקופתית', 'לוח בקרת אש חייב להיות פעיל 24/7, כולל גיבוי סוללה ל-24 שעות, ולעבור בדיקה תקופתית', true, 'critical');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'כיבוי אש', '**תאורת חירום לא פועלת בחדר מדרגות** — גופי תאורת חירום בחדר מדרגות לא דולקים בעת הפסקת חשמל, סוללות תקולות, או גופים שבורים. תאורת חירום חיונית לפינוי בטוח.. המלצה: החלפת גופי תאורת חירום פגומים, החלפת סוללות, בדיקת פעולה תקינה בניתוק חשמל. עלות משוערת: ₪300-₪700 (ליחידה)', '**תאורת חירום לא פועלת בחדר מדרגות** — גופי תאורת חירום בחדר מדרגות לא דולקים בעת הפסקת חשמל, סוללות תקולות, או גופים שבורים. תאורת חירום חיונית לפינוי בטוח.. המלצה: החלפת גופי תאורת חירום פגומים, החלפת סוללות, בדיקת פעולה תקינה בניתוק חשמל. עלות משוערת: ₪300-₪700 (ליחידה)', 'ת"י 23 — תאורת חירום נדרשת בכל מסלולי המילוט, עוצמה מינימלית של 1 לוקס ברצפה, זמן פעולה מינימלי 60 דקות', 'ת"י 23 — תאורת חירום נדרשת בכל מסלולי המילוט, עוצמה מינימלית של 1 לוקס ברצפה, זמן פעולה מינימלי 60 דקות', true, 'critical');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'כיבוי אש', '**שילוט יציאת חירום חסר או לא מואר** — שלט יציאת חירום (EXIT) חסר, לא מואר, או שהכיתוב לא קריא. שילוט חירום הוא חלק ממערך הפינוי ומחויב בכל מסלול מילוט.. המלצה: התקנת שלט יציאת חירום מואר LED עם סוללת גיבוי, בהתאם למיקום ולכיוון הפינוי. עלות משוערת: ₪250-₪600 (ליחידה)', '**שילוט יציאת חירום חסר או לא מואר** — שלט יציאת חירום (EXIT) חסר, לא מואר, או שהכיתוב לא קריא. שילוט חירום הוא חלק ממערך הפינוי ומחויב בכל מסלול מילוט.. המלצה: התקנת שלט יציאת חירום מואר LED עם סוללת גיבוי, בהתאם למיקום ולכיוון הפינוי. עלות משוערת: ₪250-₪600 (ליחידה)', 'ת"י 23 — שילוט יציאת חירום מואר נדרש בכל נקודות היציאה ובכל נקודת החלטה במסלול המילוט', 'ת"י 23 — שילוט יציאת חירום מואר נדרש בכל נקודות היציאה ובכל נקודת החלטה במסלול המילוט', true, 'medium');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'כיבוי אש', '**צנרת כיבוי אש (standpipe) חלודה או דולפת** — צנרת כיבוי אש עולה (standpipe) בחדר מדרגות מראה סימני חלודה, דליפות, או שברזי הפיתוח שלה חסומים.. המלצה: החלפת קטעי צנרת חלודים, תיקון דליפות, שיפוץ או החלפת ברזי פיתוח, צביעה בצבע אדום. עלות משוערת: ₪800-₪3000 (ליחידה)', '**צנרת כיבוי אש (standpipe) חלודה או דולפת** — צנרת כיבוי אש עולה (standpipe) בחדר מדרגות מראה סימני חלודה, דליפות, או שברזי הפיתוח שלה חסומים.. המלצה: החלפת קטעי צנרת חלודים, תיקון דליפות, שיפוץ או החלפת ברזי פיתוח, צביעה בצבע אדום. עלות משוערת: ₪800-₪3000 (ליחידה)', 'צנרת כיבוי אש חייבת להיות תקינה, ללא דליפות, עם ברזי פיתוח נגישים ותקינים בכל קומה', 'צנרת כיבוי אש חייבת להיות תקינה, ללא דליפות, עם ברזי פיתוח נגישים ותקינים בכל קומה', true, 'medium');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'כיבוי אש', '**חניון ללא מערכת אוורור מכני** — חניון תת-קרקעי ללא מערכת אוורור מכני פעילה, או שהמערכת תקולה. הצטברות פליטות רכב ועשן מהווה סכנת חיים.. המלצה: תיקון מערכת אוורור מכני, החלפת מנועים תקולים, ניקוי תעלות, בדיקת בקר CO. עלות משוערת: ₪3000-₪15000 (ליחידה)', '**חניון ללא מערכת אוורור מכני** — חניון תת-קרקעי ללא מערכת אוורור מכני פעילה, או שהמערכת תקולה. הצטברות פליטות רכב ועשן מהווה סכנת חיים.. המלצה: תיקון מערכת אוורור מכני, החלפת מנועים תקולים, ניקוי תעלות, בדיקת בקר CO. עלות משוערת: ₪3000-₪15000 (ליחידה)', 'חניון תת-קרקעי חייב במערכת אוורור מכני המבטיחה החלפת אוויר מספקת ופינוי עשן בשריפה', 'חניון תת-קרקעי חייב במערכת אוורור מכני המבטיחה החלפת אוויר מספקת ופינוי עשן בשריפה', true, 'critical');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'כיבוי אש', '**מערכת גילוי CO בחניון לא פעילה** — מערכת גילוי פחמן חד-חמצני (CO) בחניון תת-קרקעי לא פעילה, חיישנים תקולים, או ללא חיבור למערכת אוורור.. המלצה: תיקון או החלפת חיישני CO, בדיקת חיבור למערכת אוורור, כיול חיישנים. עלות משוערת: ₪1000-₪3000 (ליחידה)', '**מערכת גילוי CO בחניון לא פעילה** — מערכת גילוי פחמן חד-חמצני (CO) בחניון תת-קרקעי לא פעילה, חיישנים תקולים, או ללא חיבור למערכת אוורור.. המלצה: תיקון או החלפת חיישני CO, בדיקת חיבור למערכת אוורור, כיול חיישנים. עלות משוערת: ₪1000-₪3000 (ליחידה)', 'חניון תת-קרקעי חייב במערכת גילוי CO המחוברת להפעלה אוטומטית של מערכת האוורור', 'חניון תת-קרקעי חייב במערכת גילוי CO המחוברת להפעלה אוטומטית של מערכת האוורור', true, 'medium');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'מעלית', '**מעלית ללא תעודת בדיקה בתוקף** — תעודת בדיקה תקופתית של המעלית פגת תוקף או לא מוצגת בתוך תא המעלית. בדיקה תקופתית חובה לפי חוק.. המלצה: הזמנת בדיקת מעלית תקופתית מבודק מוסמך, תיקון ליקויים שיימצאו, והצגת תעודה בתוקף בתא. עלות משוערת: ₪600-₪1500 (ליחידה)', '**מעלית ללא תעודת בדיקה בתוקף** — תעודת בדיקה תקופתית של המעלית פגת תוקף או לא מוצגת בתוך תא המעלית. בדיקה תקופתית חובה לפי חוק.. המלצה: הזמנת בדיקת מעלית תקופתית מבודק מוסמך, תיקון ליקויים שיימצאו, והצגת תעודה בתוקף בתא. עלות משוערת: ₪600-₪1500 (ליחידה)', 'ת"י 7588 — מעלית חייבת לעבור בדיקה תקופתית כל 6 חודשים על ידי בודק מוסמך, ותעודת הבדיקה חייבת להיות מוצגת בתא', 'ת"י 7588 — מעלית חייבת לעבור בדיקה תקופתית כל 6 חודשים על ידי בודק מוסמך, ותעודת הבדיקה חייבת להיות מוצגת בתא', true, 'medium');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'מעלית', '**דלת מעלית לא נסגרת כראוי** — דלת תא מעלית או דלת פיר לא נסגרת באופן מלא, נתקעת, או סוגרת בכוח מוגזם. דלת לא תקינה מהווה סכנת בטיחות וגורמת לתקלות חוזרות.. המלצה: כוונון או החלפת מנגנון דלת מעלית, ניקוי מסילות, החלפת גלגלים בלויים, בדיקת חיישן בטיחות. עלות משוערת: ₪800-₪2500 (ליחידה)', '**דלת מעלית לא נסגרת כראוי** — דלת תא מעלית או דלת פיר לא נסגרת באופן מלא, נתקעת, או סוגרת בכוח מוגזם. דלת לא תקינה מהווה סכנת בטיחות וגורמת לתקלות חוזרות.. המלצה: כוונון או החלפת מנגנון דלת מעלית, ניקוי מסילות, החלפת גלגלים בלויים, בדיקת חיישן בטיחות. עלות משוערת: ₪800-₪2500 (ליחידה)', 'ת"י 7588 — דלתות מעלית חייבות לפעול בצורה חלקה, לסגור באופן מלא, ולכלול מנגנון בטיחות למניעת לכידה', 'ת"י 7588 — דלתות מעלית חייבות לפעול בצורה חלקה, לסגור באופן מלא, ולכלול מנגנון בטיחות למניעת לכידה', true, 'medium');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'מעלית', '**כפתור מעלית לא פועל או שבור** — כפתור קריאה בקומה או כפתור בחירת קומה בתא המעלית לא פועל, שקוע, שבור, או ללא תאורה.. המלצה: החלפת כפתור מעלית פגום, בדיקת חיווט, וודאות תקינות תאורת אינדיקציה. עלות משוערת: ₪200-₪600 (ליחידה)', '**כפתור מעלית לא פועל או שבור** — כפתור קריאה בקומה או כפתור בחירת קומה בתא המעלית לא פועל, שקוע, שבור, או ללא תאורה.. המלצה: החלפת כפתור מעלית פגום, בדיקת חיווט, וודאות תקינות תאורת אינדיקציה. עלות משוערת: ₪200-₪600 (ליחידה)', 'כל כפתורי המעלית חייבים לפעול באופן תקין ולתת אינדיקציה ויזואלית על לחיצה', 'כל כפתורי המעלית חייבים לפעול באופן תקין ולתת אינדיקציה ויזואלית על לחיצה', true, 'medium');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'מעלית', '**טלפון חירום במעלית לא פועל** — טלפון חירום (אינטרקום) בתא מעלית לא מחובר, לא פועל, או לא מגיע ליעד (מוקד חילוץ). טלפון חירום חיוני לחילוץ נלכדים.. המלצה: תיקון או החלפת מערכת אינטרקום, בדיקת קו טלפון, וידוא חיבור למוקד חילוץ. עלות משוערת: ₪500-₪1500 (ליחידה)', '**טלפון חירום במעלית לא פועל** — טלפון חירום (אינטרקום) בתא מעלית לא מחובר, לא פועל, או לא מגיע ליעד (מוקד חילוץ). טלפון חירום חיוני לחילוץ נלכדים.. המלצה: תיקון או החלפת מערכת אינטרקום, בדיקת קו טלפון, וידוא חיבור למוקד חילוץ. עלות משוערת: ₪500-₪1500 (ליחידה)', 'ת"י 7588 — כל מעלית חייבת להיות מצוידת בטלפון חירום דו-כיווני תקין המחובר למוקד 24/7', 'ת"י 7588 — כל מעלית חייבת להיות מצוידת בטלפון חירום דו-כיווני תקין המחובר למוקד 24/7', true, 'critical');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'מעלית', '**תאורה לא תקינה בתא מעלית** — תאורה בתא מעלית חלשה, מהבהבת, או כבויה חלקית. כולל תאורת חירום שלא דולקת בהפסקת חשמל.. המלצה: החלפת נורות/לדים בתא מעלית, בדיקה ותיקון תאורת חירום כולל סוללה. עלות משוערת: ₪200-₪600 (ליחידה)', '**תאורה לא תקינה בתא מעלית** — תאורה בתא מעלית חלשה, מהבהבת, או כבויה חלקית. כולל תאורת חירום שלא דולקת בהפסקת חשמל.. המלצה: החלפת נורות/לדים בתא מעלית, בדיקה ותיקון תאורת חירום כולל סוללה. עלות משוערת: ₪200-₪600 (ליחידה)', 'תאורה בתא מעלית חייבת להיות בעוצמה מספקת (50 לוקס לפחות) כולל תאורת חירום עצמאית', 'תאורה בתא מעלית חייבת להיות בעוצמה מספקת (50 לוקס לפחות) כולל תאורת חירום עצמאית', true, 'medium');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'מעלית', '**מעלית ללא מפתח כיבוי אש (fireman switch)** — מעלית ללא מפתח כיבוי אש (fireman switch) או שהמפתח לא זמין לשירותי כיבוי. מפתח זה מאפשר לכבאים לשלוט במעלית בשעת חירום.. המלצה: התקנת מנגנון fireman switch תקני, מסירת מפתחות לשירותי כיבוי, סימון בולט. עלות משוערת: ₪500-₪1500 (ליחידה)', '**מעלית ללא מפתח כיבוי אש (fireman switch)** — מעלית ללא מפתח כיבוי אש (fireman switch) או שהמפתח לא זמין לשירותי כיבוי. מפתח זה מאפשר לכבאים לשלוט במעלית בשעת חירום.. המלצה: התקנת מנגנון fireman switch תקני, מסירת מפתחות לשירותי כיבוי, סימון בולט. עלות משוערת: ₪500-₪1500 (ליחידה)', 'ת"י 7588 — מעלית חייבת להיות מצוידת במתג כבאים (fireman switch) בקומת הכניסה המאפשר הפעלת מצב חירום', 'ת"י 7588 — מעלית חייבת להיות מצוידת במתג כבאים (fireman switch) בקומת הכניסה המאפשר הפעלת מצב חירום', true, 'medium');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'מעלית', '**מעלית — רעש חריג או רעידות** — מעלית עם רעש חריג, רעידות או נסיעה לא חלקה.. המלצה: בדיקת טכנאי מעליות, תיקון לפי ממצאים. עלות משוערת: ₪500-₪3000 (ליחידה)', '**מעלית — רעש חריג או רעידות** — מעלית עם רעש חריג, רעידות או נסיעה לא חלקה.. המלצה: בדיקת טכנאי מעליות, תיקון לפי ממצאים. עלות משוערת: ₪500-₪3000 (ליחידה)', 'ת"י 20 — מעלית חייבת לפעול בשקט ובחלקות', 'ת"י 20 — מעלית חייבת לפעול בשקט ובחלקות', true, 'medium');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'חדר מדרגות', '**מעקה חדר מדרגות רופף או בגובה לא תקני** — מעקה בחדר מדרגות רופף, לא יציב, או בגובה נמוך מהנדרש (פחות מ-105 ס"מ). מעקה לא תקין מהווה סכנת נפילה.. המלצה: חיזוק עיגון מעקה, הגבהה לגובה תקני של 105 ס"מ, ותיקון חלקים רופפים. עלות משוערת: ₪500-₪2000 (למ"א)', '**מעקה חדר מדרגות רופף או בגובה לא תקני** — מעקה בחדר מדרגות רופף, לא יציב, או בגובה נמוך מהנדרש (פחות מ-105 ס"מ). מעקה לא תקין מהווה סכנת נפילה.. המלצה: חיזוק עיגון מעקה, הגבהה לגובה תקני של 105 ס"מ, ותיקון חלקים רופפים. עלות משוערת: ₪500-₪2000 (למ"א)', 'ת"י 1142 — מעקה בטיחות בחדר מדרגות חייב להיות בגובה 105 ס"מ לפחות, יציב, ועם מרווחים בין חלקיו שלא יעלו על 10 ס"מ', 'ת"י 1142 — מעקה בטיחות בחדר מדרגות חייב להיות בגובה 105 ס"מ לפחות, יציב, ועם מרווחים בין חלקיו שלא יעלו על 10 ס"מ', true, 'medium');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'חדר מדרגות', '**מדרגה שבורה או סדוקה בחדר מדרגות** — מדרגת שיש או בטון סדוקה, שבורה, או עם חלקים חסרים בחדר המדרגות. מדרגה פגומה מהווה סכנת מעידה.. המלצה: תיקון או החלפת מדרגה פגומה, מילוי סדקים באפוקסי או החלפת אריח שיש. עלות משוערת: ₪300-₪900 (ליחידה)', '**מדרגה שבורה או סדוקה בחדר מדרגות** — מדרגת שיש או בטון סדוקה, שבורה, או עם חלקים חסרים בחדר המדרגות. מדרגה פגומה מהווה סכנת מעידה.. המלצה: תיקון או החלפת מדרגה פגומה, מילוי סדקים באפוקסי או החלפת אריח שיש. עלות משוערת: ₪300-₪900 (ליחידה)', 'תקנות הבנייה מחייבות מדרגות שלמות ויציבות בכל חלקי המבנה הציבוריים', 'תקנות הבנייה מחייבות מדרגות שלמות ויציבות בכל חלקי המבנה הציבוריים', true, 'medium');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'חדר מדרגות', '**פס נגד החלקה חסר במדרגות** — פס נגד החלקה (anti-slip nosing) חסר בקצה המדרגות בחדר המדרגות. העדר פס נגד החלקה מגביר סכנת מעידה, במיוחד כשהמדרגות רטובות.. המלצה: התקנת פסי אלומיניום נגד החלקה עם תוספת גומי בקצה כל מדרגה. עלות משוערת: ₪40-₪80 (למ"א)', '**פס נגד החלקה חסר במדרגות** — פס נגד החלקה (anti-slip nosing) חסר בקצה המדרגות בחדר המדרגות. העדר פס נגד החלקה מגביר סכנת מעידה, במיוחד כשהמדרגות רטובות.. המלצה: התקנת פסי אלומיניום נגד החלקה עם תוספת גומי בקצה כל מדרגה. עלות משוערת: ₪40-₪80 (למ"א)', 'ת"י 1142 — נדרש סימון בולט ונגד החלקה בקצה כל מדרגה בחדר מדרגות ציבורי', 'ת"י 1142 — נדרש סימון בולט ונגד החלקה בקצה כל מדרגה בחדר מדרגות ציבורי', true, 'medium');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'חדר מדרגות', '**צביעה מתקלפת או לכלוך בחדר מדרגות** — צבע מתקלף, כתמים, גרפיטי, או לכלוך מצטבר על קירות חדר המדרגות. מצב זה מעיד על חוסר תחזוקה.. המלצה: הכנת משטחים (גירוד, שפכטל), צביעה מחדש בצבע פלסטי עמיד בגוון אחיד. עלות משוערת: ₪25-₪55 (למ"ר)', '**צביעה מתקלפת או לכלוך בחדר מדרגות** — צבע מתקלף, כתמים, גרפיטי, או לכלוך מצטבר על קירות חדר המדרגות. מצב זה מעיד על חוסר תחזוקה.. המלצה: הכנת משטחים (גירוד, שפכטל), צביעה מחדש בצבע פלסטי עמיד בגוון אחיד. עלות משוערת: ₪25-₪55 (למ"ר)', 'שטחים ציבוריים חייבים להישמר במצב תקין ונקי כחלק מתחזוקת הרכוש המשותף', 'שטחים ציבוריים חייבים להישמר במצב תקין ונקי כחלק מתחזוקת הרכוש המשותף', true, 'low');
